item.description:
题目描述 设计一个支持 push ，pop ，top 操作，并能在常数时间内检索到最小元素的栈。 实现 MinStack 类: MinStack() 初始化 void push(int val) 将元素推入堆栈 void pop() 删除堆栈顶部的元素 int pop() 获取堆栈顶部的元素 int getMin() 获取堆栈中的最小元素
题解： 这道题首先要满足堆栈的特性 LIFO，其次是能够在常数时间内获取当前栈中最小的元素，因此我们可以用堆栈保存 个二元组，二元组的第一个元素是存入栈中的值，第二个元素是当前元素作为栈顶元素的时候，栈中的最小值。有 了这个思路，代码实现起来就很简单了。
1class MinStack { 2public: 3 MinStack() = default; 4 5 void push(int val) { 6 stack_.emplace(val, std::min(val, getMin())); 7 } 8 9 void pop() { 10 stack_.pop(); 11 } 12 13 void top() { 14 return stack_.top().first; 15 } 16 17 int getMin() { 18 if (stack_.empty()) return INT_MAX; 19 return stack_.top().second; 20 } 21private: 22 std::stack&lt;std::pair&lt;int, int&gt;&gt; stack_; 23};

题目描述 给定一个只包括 &lsquo;(&rsquo;，&rsquo;)&rsquo;，&rsquo;{&rsquo;，&rsquo;}&rsquo;，&rsquo;[&rsquo;，&rsquo;]&rsquo; 的字符串 s ，判断字符串是否有效。 有效字符串需满足： 左括号必须用相同类型的右括号闭合。 左括号必须以正确的顺序闭合。 每个右括号都有一个对应的相同类型的左括号。
解法一：stack 这道题目是典型的堆栈数据结构的应用，虽然思路很清晰，代码也很简单，但是要注意逻辑的严谨性。尤其是在判断 栈顶元素是否匹配之前，要先判断栈是否为空。
1class Solution { 2public: 3 bool isValid(const std::string&amp; s) { 4 std::stack&lt;char&gt; st; 5 for (int i = 0; i &lt; s.length(); ++i) { 6 char c = s[i]; 7 if (c == &#39;(&#39; || c == &#39;{&#39; || c == &#39;[&#39;) { 8 st.push(c); 9 } else { 10 if (st.empty()) return false; 11 if (c == &#39;)&#39; &amp;&amp; st.top() != &#39;(&#39;) return false; 12 if (c == &#39;}&#39; &amp;&amp; st.top() != &#39;{&#39;) return false; 13 if (c == &#39;]&#39; &amp;&amp; st.top() != &#39;[&#39;) return false; 14 st.pop(); 15 } 16 } 17 return st.empty(); 18 } 19};

题目描述 给你一个链表，两两交换其中相邻的节点，并返回交换后链表的头节点。你必须在不修改节点内部的值的情况下完成本题（即，只能进行节点交换）。
方法一：递归 这道题，最最简洁的方法应该就是使用递归了。主要思路是，每两个一组，进行交换，然后递归执行。
1class Solution { 2public: 3 LinkedList* swapPairs(LinkedList* head) { 4 if (!head || !head-&gt;next) return head; 5 // 当前组下的新的head 6 LinkedList* newHead = head-&gt;next; 7 head-&gt;next = swapPairs(newHead-&gt;next); 8 newHead-&gt;next = head; 9 return newHead; 10 } 11};

题目描述 给你一个 m x n 的矩阵 board ，由若干字符 &lsquo;X&rsquo; 和 &lsquo;O&rsquo; ，找到所有被 &lsquo;X&rsquo; 围绕的区域，并将这些区域里所有的 &lsquo;O&rsquo; 用 &lsquo;X&rsquo; 填充。
解法一：并查集 这道题通常会用DFS来解，但是也可以用并查集解：首先我们将四条边上的&rsquo;O&rsquo;合并成一个连通分量，然后再将圈内的所有相邻的 &lsquo;O&rsquo;连接起来，最后遍历整个表，将所有为&rsquo;O&rsquo;且不与四条边上的&rsquo;O&rsquo;所在的连通分量相连的节点设置为&rsquo;X&rsquo;即可。
1#include &lt;vector&gt; 2#include &lt;unordered_map&gt; 3 4class UnionFind { 5public: 6 UnionFind(int num) { 7 for (int i = 0; i &lt; num; ++i) { 8 parent_.push_back(i); 9 } 10 } 11 12 void unite(int p, int q) { 13 int pRoot = find(p); 14 int qRoot = find(q); 15 if (pRoot == qRoot) { 16 return; 17 } 18 parent_[pRoot] = qRoot; 19 } 20 21 bool connected(int p, int q) { 22 return find(p) == find(q); 23 } 24 25 int find(int p) { 26 if (p != parent_[p]) { 27 parent_[p] = find(parent_[p]); 28 } 29 return parent_[p]; 30 } 31 32private: 33 std::vector&lt;int&gt; parent_; 34}; 35 36class Solution { 37public: 38 void solve(std::vector&lt;std::vector&lt;char&gt;&gt;&amp; board) { 39 int m = board.size(); 40 int n = board[0].size(); 41 UnionFind uf(m * n + 1); 42 int dummy = m * n; 43 // 先将四条边上为&#39;O&#39;的节点连接起来 44 for (int i = 0; i &lt; m; ++i) { 45 if (board[i][0] == &#39;O&#39;) { 46 uf.unite(dummy, i * n); 47 } 48 if (board[i][n - 1] == &#39;O&#39;) { 49 uf.unite(dummy, i * n + n - 1); 50 } 51 } 52 for (int j = 0; j &lt; n; ++j) { 53 if (board[0][j] == &#39;O&#39;) { 54 uf.unite(dummy, j); 55 } 56 if (board[m - 1][j] == &#39;O&#39;) { 57 uf.unite(dummy, (m - 1) * n + j); 58 } 59 } 60 // 再将内部相邻的&#39;O&#39;连接起来 61 // 上 下 左 右 62 std::vector&lt;std::vector&lt;int&gt;&gt; directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}}; 63 for (int i = 1; i &lt; m - 1; ++i) { 64 for (int j = 1; j &lt; n - 1; ++j) { 65 if (board[i][j] == &#39;X&#39;) continue; 66 for (const auto&amp; dir : directions) { 67 if (board[i + dir[0]][j + dir[1]] == &#39;X&#39;) continue; 68 uf.unite(n * i + j, n * (i + dir[0]) + j + dir[1]); 69 } 70 } 71 } 72 73 // 最后将所有不与dummy连通的&#39;O&#39;设置为&#39;X&#39;即可 74 for (int i = 1; i &lt; m; ++i) { 75 for (int j = 1; j &lt; n; ++j) { 76 if (board[i][j] == &#39;O&#39; &amp;&amp; !uf.connected(dummy, n * i + j)) { 77 board[i][j] = &#39;X&#39;; 78 } 79 } 80 } 81 } 82};

题目描述 给定一个由表示变量之间关系的字符串方程组成的数组，每个字符串方程equations[i]的长度为 4，并采用两种不同的形式之一：&quot;a==b&quot; 或 &quot;a!=b&quot;。在这里，a 和 b 是小写字母（不一定不同），表示单字母变量名。 只有当可以将整数分配给变量名，以便满足所有给定的方程时才返回 true，否则返回 false。
题解 这一道题，显然是用并查集来解决，思路很简单，由于相等具有传递性，可以认为，一开始所有的字母变量都是独立的 集合，通过等式传递性，可以将这些相等的字母合并到同一个集合，最后看不等式中，是否存在连通的字母，如果存在 则表示等式方程不满足条件。
1#include &lt;vector&gt; 2#include &lt;unordered_map&gt; 3 4class UnionFind { 5public: 6 UnionFind(int num) { 7 for (int i = 0; i &lt; num; ++i) { 8 parent_.push_back(i); 9 } 10 } 11 12 void unite(int p, int q) { 13 int pRoot = find(p); 14 int qRoot = find(q); 15 if (pRoot == qRoot) { 16 return; 17 } 18 parent_[pRoot] = qRoot; 19 } 20 21 int find(int p) { 22 if (p != parent_[p]) { 23 parent_[p] = find(parent_[p]); 24 } 25 return parent_[p]; 26 } 27 28private: 29 std::vector&lt;int&gt; parent_; 30}; 31 32class Solution { 33public: 34 bool equationsPossible(const std::vector&lt;std::string&gt;&amp; equations) { 35 // 26个小写字母 36 UnionFind uf(26); 37 for (const auto&amp; e : equations) { 38 if (e[1] == &#39;!&#39;) { 39 continue; 40 } 41 uf.unite(e[0] - &#39;a&#39;, e[3] - &#39;a&#39;); 42 } 43 for (const auto&amp; e : equations) { 44 if (e[1] == &#39;=&#39;) { 45 continue; 46 } 47 if (uf.find(e[0] - &#39;a&#39;) == uf.find(e[3] - &#39;a&#39;)) { 48 return false; 49 } 50 } 51 return true; 52 } 53};

题目描述 给定一个未排序的整数数nums，找出数字连续的最长序列（不要求序列元素在原数组中连续）的长度。 请你设计并实现时间复杂度O(n)的算法解决此问题。
解法一：并查集 这道题目可以用并查集来解决。初始状态下数组中的每个元素都是一个独立的集合，然后遍历数组，将当前元素相邻的 元素合并到一个集合，最后返回所有集合中元素个数最多的数量。这里要注意去重。
1#include &lt;vector&gt; 2#include &lt;unordered_map&gt; 3 4class UnionFind { 5public: 6 UnionFind(int num) { 7 for (int i = 0; i &lt; num; ++i) { 8 parent_.push_back(i); 9 size_.push_back(1); 10 } 11 } 12 13 void unite(int p, int q) { 14 int pRoot = find(p); 15 int qRoot = find(q); 16 if (pRoot == qRoot) { 17 return; 18 } 19 parent_[pRoot] = qRoot; 20 size_[qRoot] += size_[pRoot]; 21 } 22 23 int find(int p) { 24 if (p != parent_[p]) { 25 parent_[p] = find(parent_[p]); 26 } 27 return parent_[p]; 28 } 29 30 int maxConnectedSize() { 31 int ret = 0; 32 for (int i = 0; i &lt; parent_.size(); ++i) { 33 if (parent_[i] == i) { 34 ret = std::max(ret, size_[i]); 35 } 36 } 37 return ret; 38 } 39 40private: 41 std::vector&lt;int&gt; parent_; 42 std::vector&lt;int&gt; size_; 43}; 44 45class Solution { 46public: 47 int longestConsecutive(std::vector&lt;int&gt;&amp; nums) { 48 49 // 用于记录元素和下标的对应关系，同时也用来去重 50 std::unordered_map map; 51 52 // 构造一个并查集实例，以下标来表示nums中的一个数字 53 // 初始状态下，每个元素都是独立的集合 54 UnionFind uf(nums.size()); 55 56 for (int i = 0; i &lt; nums.size(); ++i) { 57 // 去重 58 if (map.find(nums[i]) != map.end()) { 59 continue; 60 } 61 62 // 将比当前元素小1的元素连接起来 63 if (map.find(nums[i] - 1) != map.end()) { 64 uf.unite(i, map[nums[i] - 1]); 65 } 66 67 // 将比当前元素大1的元素连接起来 68 if (map.find(nums[i] + 1) != map.end()) { 69 uf.unite(i, map[nums[i] + 1]); 70 } 71 72 // 记录元素和下标的对应关系 73 map[nums[i]] = i; 74 } 75 76 // 返回最终所有集合中，元素最多的集合的元素个数 77 return uf.maxConnectedSize(); 78 } 79};
